/**
 * Phase D — Database Migrations
 *
 * Runs database migrations via the MemberJunction CLI's `migrate` command,
 * which invokes node-flyway under the hood to apply pending SQL migration
 * scripts from the `migrations/` directory.
 *
 * The migration command reads database connection settings from the `.env`
 * file generated by the configure phase. It applies all pending migrations
 * in version order, creating the `__mj` schema tables, stored procedures,
 * views, and seed data that MemberJunction requires.
 *
 * **CLI resolution**: Uses the local `@memberjunction/cli` binary installed
 * as a workspace dependency in the monorepo.
 *
 * @module phases/MigratePhase
 * @see ConfigurePhase — generates the `.env` file with database credentials.
 * @see DatabaseProvisionPhase — creates the database and SQL logins used by migrations.
 */

import path from 'node:path';
import type { InstallerEventEmitter } from '../events/InstallerEvents.js';
import type { PartialInstallConfig } from '../models/InstallConfig.js';
import { InstallerError } from '../errors/InstallerError.js';
import { ProcessRunner } from '../adapters/ProcessRunner.js';
import { FileSystemAdapter } from '../adapters/FileSystemAdapter.js';

/**
 * Input context for the migrate phase.
 *
 * @see MigratePhase.Run
 */
export interface MigrateContext {
  /** Absolute path to the repo root (where migrations are executed). */
  Dir: string;
  /** Current install config (used for diagnostic context, not directly by migrations). */
  Config: PartialInstallConfig;
  /** Event emitter for progress and log events. */
  Emitter: InstallerEventEmitter;
  /**
   * Release version tag (e.g., `"v5.9.0"`). Used to pin the CLI version
   * when falling back to `npx @memberjunction/cli@<version>`.
   */
  VersionTag?: string;
}

/**
 * Result of the migrate phase.
 *
 * @see MigratePhase.Run
 */
export interface MigrateResult {
  /** Whether all migrations completed successfully. */
  Success: boolean;
  /** Raw stdout output from the migration command. */
  Output: string;
}

/**
 * Default migration timeout in minutes. First-install on a slow Docker SQL
 * Server can take 20+ minutes due to the size of the metadata-sync migrations
 * (~30 MB SQL files inserting tens of thousands of rows). Override via the
 * `MJ_INSTALL_MIGRATE_TIMEOUT_MIN` environment variable when shipping in even
 * slower CI / VM environments.
 */
const DEFAULT_MIGRATE_TIMEOUT_MIN = 30;

/** Resolve the configured migrate timeout in milliseconds. */
function resolveMigrateTimeoutMs(): number {
  const raw = process.env.MJ_INSTALL_MIGRATE_TIMEOUT_MIN;
  if (raw) {
    const parsed = parseInt(raw, 10);
    if (Number.isFinite(parsed) && parsed > 0) {
      return parsed * 60_000;
    }
  }
  return DEFAULT_MIGRATE_TIMEOUT_MIN * 60_000;
}

/**
 * Phase D — Runs database migrations via the MemberJunction CLI.
 *
 * @example
 * ```typescript
 * const migrate = new MigratePhase();
 * const result = await migrate.Run({
 *   Dir: '/path/to/install',
 *   Config: { DatabaseHost: 'localhost' },
 *   Emitter: emitter,
 *   VersionTag: 'v5.9.0',
 * });
 * console.log(result.Success ? 'Migrations applied' : 'Migration failed');
 * ```
 */
export class MigratePhase {
  private processRunner = new ProcessRunner();
  private fileSystem = new FileSystemAdapter();

  /**
   * Execute database migrations.
   *
   * The timeout defaults to {@link DEFAULT_MIGRATE_TIMEOUT_MIN} minutes and
   * can be raised via the `MJ_INSTALL_MIGRATE_TIMEOUT_MIN` environment
   * variable for slower environments (e.g., Docker SQL Server on Windows).
   *
   * @param context - Migrate input with directory, config, and emitter.
   * @returns Migration result with success status and raw output.
   * @throws {InstallerError} With code `MIGRATE_TIMEOUT` if migrations exceed
   *   the configured timeout (default: 30 minutes).
   * @throws {InstallerError} With code `MIGRATE_FAILED` if the migration
   *   command exits non-zero.
   */
  async Run(context: MigrateContext): Promise<MigrateResult> {
    const { Emitter: emitter } = context;

    const timeoutMs = resolveMigrateTimeoutMs();
    const timeoutMin = Math.round(timeoutMs / 60_000);

    emitter.Emit('step:progress', {
      Type: 'step:progress',
      Phase: 'migrate',
      Message: `Running database migrations (timeout: ${timeoutMin} min)...`,
    });

    const { cmd, args } = await this.resolveCli(context.Dir, context.VersionTag, ['migrate', '--verbose']);

    const result = await this.processRunner.Run(cmd, args, {
      Cwd: context.Dir,
      TimeoutMs: timeoutMs,
      OnStdout: (line: string) => {
        emitter.Emit('step:progress', {
          Type: 'step:progress',
          Phase: 'migrate',
          Message: line.trim(),
        });
      },
      OnStderr: (line: string) => {
        emitter.Emit('log', {
          Type: 'log',
          Level: 'verbose',
          Message: `[migrate:stderr] ${line.trim()}`,
        });
      },
    });

    if (result.TimedOut) {
      throw new InstallerError(
        'migrate',
        'MIGRATE_TIMEOUT',
        `Database migration timed out after ${timeoutMin} minutes.`,
        `Raise the timeout with MJ_INSTALL_MIGRATE_TIMEOUT_MIN=<minutes> for slow environments, or run "mj migrate" manually to see detailed output. Also check database connectivity.`
      );
    }

    if (result.ExitCode !== 0) {
      // Combine stdout and stderr for full diagnostic output — Flyway errors go to stderr
      const combined = [result.Stdout, result.Stderr].filter(Boolean).join('\n');
      const lastLines = this.lastNLines(combined, 80);
      throw new InstallerError(
        'migrate',
        'MIGRATE_FAILED',
        `Database migration failed (exit code ${result.ExitCode}):\n${lastLines}`,
        'Check the migration output above. Common issues: database connectivity, incorrect credentials, or SQL syntax errors.'
      );
    }

    emitter.Emit('log', {
      Type: 'log',
      Level: 'info',
      Message: 'Database migrations completed successfully.',
    });

    return {
      Success: true,
      Output: result.Stdout,
    };
  }

  // ---------------------------------------------------------------------------
  // CLI resolution
  // ---------------------------------------------------------------------------

  /**
   * Resolve the CLI command and arguments.
   *
   * Tries the local CLI binary first (monorepo or distribution with hoisted CLI).
   * Falls back to `npx @memberjunction/cli@<version>` for the distribution layout.
   *
   * @param dir - Repo root directory.
   * @param versionTag - Release tag (e.g., `"v5.9.0"`) for version pinning.
   * @param cliArgs - Arguments to pass to the CLI (e.g., `['migrate', '--verbose']`).
   * @returns Command and args array suitable for `ProcessRunner.Run()`.
   */
  private async resolveCli(
    dir: string,
    versionTag: string | undefined,
    cliArgs: string[]
  ): Promise<{ cmd: string; args: string[] }> {
    const candidates = [
      path.join(dir, 'node_modules', '@memberjunction', 'cli', 'bin', 'run.js'),
      path.join(dir, 'apps', 'MJAPI', 'node_modules', '@memberjunction', 'cli', 'bin', 'run.js'),
    ];

    for (const localCli of candidates) {
      if (await this.fileSystem.FileExists(localCli)) {
        return { cmd: 'node', args: [localCli, ...cliArgs] };
      }
    }

    // Fall back to npx with version pinning (distribution layout)
    const cliPackage = versionTag
      ? `@memberjunction/cli@${versionTag.replace(/^v/, '')}`
      : '@memberjunction/cli';

    return { cmd: 'npx', args: [cliPackage, ...cliArgs] };
  }

  // ---------------------------------------------------------------------------
  // Helpers
  // ---------------------------------------------------------------------------

  private lastNLines(text: string, n: number): string {
    const lines = text.split('\n');
    return lines.slice(-n).join('\n');
  }
}
